  console.log("¡Riégala ya!");
}
// Como 4 > 3 es verdad, se muestra el aviso

const estado = "pendiente";

console.log(5 > 3);            // true
console.log(estado === "listo");  // false
console.log(estado !== "listo");  // true

// = asigna, === compara. ¡No los mezcles!

const diasSinAgua = 2;
let aviso;

if (diasSinAgua > 3) {
  aviso = "¡Riégala ya!";
} else if (diasSinAgua > 1) {
  aviso = "Pronto tocará";
} else {
  aviso = "Todo bien";
}

console.log(aviso);   // "Pronto tocará"

const diasSinAgua = 5;
const esVerano = true;

if (diasSinAgua > 3 && esVerano) {
  console.log("Riega más: sol y sed");
}

// || : con que se cumpla una, basta
if (diasSinAgua > 7 || !esVerano) {
  console.log("Revisa esta planta");
}

const pagado = false;

// if/else de toda la vida:
let estado;
if (pagado) { estado = "listo"; } else { estado = "pendiente"; }

// lo mismo, en una línea con ternario:
const estado2 = pagado ? "listo" : "pendiente";
console.log(estado2);   // "pendiente"

